$('.popup-priview').click();

$(document).ready(function () {

  var originalImagePath = $(".popup-priview").find('img').data('image');
  $(".popup-priview").zoom({ url: originalImagePath });

  $(".btn-preview").click(function () {
    $('.wrap-priview').addClass('pop-active');
  });

  $(".btn-close").click(function () {
    $('.wrap-priview').removeClass('pop-active');
  });


  $(".dwn").click(function () {

    const fontBase64 = "data:application/font-woff;base64,";
    
    window.jsPDF = window.jspdf.jsPDF;
    var docpdf = new jsPDF();
    var elementHTML = document.querySelector("#cv");
    var invoiceNo = "MyResume";
    docpdf.html(elementHTML, {
      callback: function () {
        // Add the font to jsPDF
        docpdf.addFileToVFS("Inter-Regular.woff", fontBase64);
        docpdf.addFont("Inter-Regular.woff", "Inter-Regular", "normal");
        // Set the font
        docpdf.setFont("Inter-Regular");
        docpdf.save(invoiceNo + '.pdf');
      },
      x: 15,
      y: 15,
      width: 170,
      windowWidth: 850
    });
  });

});
